//! Place-assertion spec functions of property `failed_mode_alarm_on` -- one per
//! point its decoration binds (unbound points carry `true`, design D5).

#![allow(non_snake_case)]
#![allow(unused_imports)]

use data::*;
use vstd::prelude::*;

use crate::assertions::*;
use crate::system_state::SystemState;

verus! {

/** property failed_mode_alarm_on, bound 'after oi' (place after_oi)
  *   OI integration and alarm range constraints
  */
pub open spec fn sys_assert_failed_mode_alarm_on_after_oi(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property failed_mode_alarm_on, bound 'at ts_oi_done' (place post_join_1)
  *   join: carried past ts
  */
pub open spec fn sys_assert_failed_mode_alarm_on_post_join_1(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property failed_mode_alarm_on, bound 'before dmf' (place before_dmf)
  *   branch entry: alarm temp constraints carry in
  */
pub open spec fn sys_assert_failed_mode_alarm_on_before_dmf(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property failed_mode_alarm_on, bound 'after dmf' (place after_dmf)
  *   frame condition preserves alarm temp constraints
  */
pub open spec fn sys_assert_failed_mode_alarm_on_after_dmf(st: SystemState) -> bool
{
  (sysProp_Allowed_LowerAlarmTempWstatus(st.lower_alarm_tempWstatus) && sysProp_Allowed_UpperAlarmTempWstatus(st.upper_alarm_tempWstatus)) &&
    sysProp_Allowed_AlarmTempWStatus_Ranges(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus)
}

/** property failed_mode_alarm_on, bound 'after mmi' (place after_mmi)
  *   derived from MMI component contract + write frame + pre-assertions;
  *   the alarm range properties hold only when the monitor interface is not failing
  *   (REQ-MMI-7 leaves the range UNSPECIFIED on failure)
  */
pub open spec fn sys_assert_failed_mode_alarm_on_after_mmi(st: SystemState) -> bool
{
  (sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && sysProp_Table_A_12_LowerAlarmTemp(st.lower_alarm_temp)) &&
        sysProp_Table_A_12_UpperAlarmTemp(st.upper_alarm_temp)))
}

/** property failed_mode_alarm_on, bound 'after mmm' (place after_mmm)
  *   frame condition preserves MMI properties;
  *   MMM additionally links NORMAL mode to the absence of interface failure
  */
pub open spec fn sys_assert_failed_mode_alarm_on_after_mmm(st: SystemState) -> bool
{
  ((sysProp_REQ_MMI_5(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.mon_interface_failure) && sysProp_REQ_MMI_6(st.lower_alarm_tempWstatus, st.upper_alarm_tempWstatus, st.lower_alarm_temp, st.upper_alarm_temp, st.mon_interface_failure)) &&
    (!(st.mon_interface_failure.flag) ==>
      ((sysProp_Figure_A_7(st.lower_alarm_temp, st.upper_alarm_temp) && sysProp_Table_A_12_LowerAlarmTemp(st.lower_alarm_temp)) &&
        sysProp_Table_A_12_UpperAlarmTemp(st.upper_alarm_temp)))) &&
    sysProp_NormalModeImpliesNoInterfaceFailure(st.monitor_mode, st.mon_interface_failure)
}

/** property failed_mode_alarm_on, bound 'after ma' (place after_ma)
  *   Failed mode implies alarm on (REQ_MA_5)
  */
pub open spec fn sys_assert_failed_mode_alarm_on_after_ma(st: SystemState) -> bool
{
  sysProp_FailedModeImpliesAlarmOn(st.monitor_mode, st.alarm_control)
}

} // verus!
